(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[538],{1203:(n,e,t)=>{"use strict";t.d(e,{MockupBuilderClient:()=>a});var o=t(5155),i=t(2115);function a(){return(0,i.useEffect)(()=>{if(!window.__novamerchMockupLoaded)if(document.querySelector('script[src*="jspdf"]'))n();else{let e=document.createElement("script");e.src="https://cdn.jsdelivr.net/npm/jspdf@2.5.2/dist/jspdf.umd.min.js",e.onload=n,e.onerror=n,document.body.appendChild(e)}function n(){let n=document.createElement("script");n.src="/mockup-builder-customer.js",n.async=!1,n.onload=()=>{window.__novamerchMockupLoaded=!0},document.body.appendChild(n)}},[]),(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)("style",{dangerouslySetInnerHTML:{__html:"\n        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\n        html, body { height: 100%; }\n\n        body {\n            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;\n            background: #060C18;\n            color: #F1F5F9;\n            overflow: hidden;\n        }\n\n        /* Mockup builder viewport shell.\n           The page lives inside this wrapper instead of styling <body> directly,\n           so the same CSS works whether the page is mounted at the document root\n           (customer site) or nested inside an admin shell that already lays out\n           its own chrome (admin panel). The shell owns the viewport-locked\n           flex column: header → product-bar → main grid → (preview rows). */\n        .mockup-shell {\n            --sum-height: 120px; /* tall enough for wrapped actions; JS overrides via --sum-height */\n            position: relative;\n            width: 100%;\n            height: 100vh;\n            display: flex;\n            flex-direction: column;\n            overflow: hidden;\n            background: #060C18;\n            color: #F1F5F9;\n            min-height: 0;\n        }\n\n        /* Admin panel mounts this page inside <main class=\"main-with-sidebar\">\n           which adds 32px of padding around the page chrome. The mockup builder\n           wants the full viewport for its own header / grid / summary, so\n           neutralise that padding and let the shell take the available height\n           next to the admin sidebar. (No-op on the customer site, which has\n           no .main-with-sidebar wrapper.) */\n        .main-with-sidebar:has(> .mockup-shell) {\n            padding: 0 !important;\n            height: 100vh;\n            overflow: hidden;\n        }\n        .main-with-sidebar > .mockup-shell { height: 100%; }\n\n        /* Header */\n        .mockup-shell header {\n            background: #0A1020;\n            border-bottom: 1px solid rgba(255,255,255,0.08);\n            padding: 0 28px;\n            height: 50px;\n            display: flex;\n            align-items: center;\n            justify-content: space-between;\n            flex-shrink: 0;\n        }\n\n        header h1 { font-size: 17px; font-weight: 700; color: #fff; letter-spacing: -0.3px; }\n        header h1 span { color: #00CFFF; }\n        header small { font-size: 12px; color: #475569; }\n\n        /* Product tab bar */\n        .product-bar {\n            background: #131313;\n            border-bottom: 1px solid rgba(255,255,255,0.08);\n            padding: 0 20px;\n            display: flex;\n            gap: 2px;\n            overflow-x: auto;\n            flex-shrink: 0;\n            scrollbar-width: thin;\n            scrollbar-color: rgba(255,255,255,0.08) transparent;\n            height: 46px;\n            align-items: flex-end;\n        }\n\n        .prod-tab {\n            padding: 8px 14px;\n            border-radius: 6px 6px 0 0;\n            border: 1px solid transparent;\n            border-bottom: none;\n            cursor: pointer;\n            font-size: 12px;\n            font-weight: 500;\n            color: #94A3B8;\n            white-space: nowrap;\n            transition: all 0.12s;\n            user-select: none;\n            display: flex;\n            align-items: center;\n            gap: 5px;\n            flex-shrink: 0;\n            height: 36px;\n        }\n\n        .prod-tab:hover:not(.active) { color: #999; background: #0A1020; }\n        .prod-tab.active { background: #1e1e1e; color: #fff; border-color: #2e2e2e; }\n        .prod-tab .ti { font-size: 14px; }\n\n        /* Main layout\n           Three-column grid: sidebar | splitter | preview. The sidebar width\n           is driven by --sidebar-width (set via JS / localStorage on drag),\n           clamped to [200px, 480px] in CSS as a defence-in-depth so a bad\n           inline value can't break the layout. The 6px middle track is the\n           draggable splitter handle (see .splitter). */\n        .main {\n            display: grid;\n            grid-template-columns: clamp(200px, var(--sidebar-width, 272px), 480px) 6px 1fr;\n            flex: 1 1 0;\n            min-height: 0;\n            overflow: hidden;\n        }\n\n        @media (max-width: 1100px) {\n            .main { --sidebar-width: 240px; }\n        }\n\n        /* Splitter — vertical drag handle between sidebar and preview.\n           Sits in the 6px middle grid track. Cyan tint on hover / active. */\n        .splitter {\n            background: transparent;\n            cursor: col-resize;\n            position: relative;\n            user-select: none;\n            touch-action: none;\n            transition: background 0.12s;\n            outline: none;\n        }\n        .splitter::before {\n            content: '';\n            position: absolute;\n            top: 0;\n            bottom: 0;\n            left: 50%;\n            width: 1px;\n            background: rgba(255,255,255,0.08);\n            transform: translateX(-0.5px);\n            transition: background 0.12s, width 0.12s;\n        }\n        .splitter:hover { background: rgba(0,207,255,0.10); }\n        .splitter:hover::before { background: rgba(0,207,255,0.6); width: 2px; }\n        .splitter:focus-visible { background: rgba(0,207,255,0.15); }\n        .splitter:focus-visible::before { background: #00CFFF; width: 2px; }\n        .splitter.dragging,\n        .splitter:active { background: rgba(0,207,255,0.18); }\n        .splitter.dragging::before,\n        .splitter:active::before { background: #00CFFF; width: 2px; }\n\n        body.splitter-dragging { cursor: col-resize !important; }\n        body.splitter-dragging * { user-select: none !important; }\n\n        @media print {\n            .splitter { display: none !important; }\n        }\n\n        /* Horizontal splitter — drag handle between the canvas stage and the\n           bottom summary bar. Same visual language as the vertical .splitter,\n           rotated 90deg: 6px tall, row-resize cursor, cyan glow on hover and\n           active, 1px center line that grows on interaction. */\n        .splitter-h {\n            background: transparent;\n            cursor: row-resize;\n            position: relative;\n            user-select: none;\n            touch-action: none;\n            transition: background 0.12s;\n            outline: none;\n            height: 6px;\n            width: 100%;\n            flex-shrink: 0;\n        }\n        .splitter-h::before {\n            content: '';\n            position: absolute;\n            left: 0;\n            right: 0;\n            top: 50%;\n            height: 1px;\n            background: rgba(255,255,255,0.08);\n            transform: translateY(-0.5px);\n            transition: background 0.12s, height 0.12s;\n        }\n        .splitter-h:hover { background: rgba(0,207,255,0.10); }\n        .splitter-h:hover::before { background: rgba(0,207,255,0.6); height: 2px; }\n        .splitter-h:focus-visible { background: rgba(0,207,255,0.15); }\n        .splitter-h:focus-visible::before { background: #00CFFF; height: 2px; }\n        .splitter-h.dragging,\n        .splitter-h:active { background: rgba(0,207,255,0.18); }\n        .splitter-h.dragging::before,\n        .splitter-h:active::before { background: #00CFFF; height: 2px; }\n\n        body.splitter-h-dragging { cursor: row-resize !important; }\n        body.splitter-h-dragging * { user-select: none !important; }\n\n        @media print {\n            .splitter-h { display: none !important; }\n        }\n\n        /* Options panel — fills its grid track and scrolls internally so the\n           page never gets pushed past the viewport on short laptop screens. */\n        .opts {\n            background: #0D1526;\n            border-right: 1px solid rgba(255,255,255,0.08);\n            overflow-y: auto;\n            overflow-x: hidden;\n            min-height: 0;\n            height: 100%;\n            padding: 18px 14px 24px;\n            padding-right: 8px;\n            scrollbar-width: thin;\n            scrollbar-color: #00CFFF #0A1020;\n        }\n\n        .opts::-webkit-scrollbar { width: 8px; }\n        .opts::-webkit-scrollbar-track { background: #0A1020; }\n        .opts::-webkit-scrollbar-thumb {\n            background: rgba(0,207,255,0.45);\n            border-radius: 4px;\n            border: 1px solid #0A1020;\n        }\n        .opts::-webkit-scrollbar-thumb:hover { background: rgba(0,207,255,0.7); }\n\n        .opt-sec { margin-bottom: 20px; }\n\n        .opt-lbl {\n            font-size: 10px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 0.9px;\n            color: #475569;\n            margin-bottom: 9px;\n        }\n\n        /* Style list */\n        .style-list { display: flex; flex-direction: column; gap: 5px; }\n\n        .style-opt {\n            padding: 8px 11px;\n            border-radius: 5px;\n            border: 1px solid #232323;\n            background: #1e1e1e;\n            color: #999;\n            font-size: 12px;\n            cursor: pointer;\n            transition: all 0.1s;\n            user-select: none;\n        }\n\n        .style-opt:hover { border-color: #363636; color: #ddd; }\n        .style-opt.sel { border-color: #00CFFF; color: #fff; background: rgba(0,207,255,0.15); }\n\n        /* Colour swatches */\n        .swatches { display: flex; flex-wrap: wrap; gap: 7px; }\n\n        .sw-wrap { position: relative; }\n\n        .swatch {\n            width: 28px;\n            height: 28px;\n            border-radius: 50%;\n            cursor: pointer;\n            border: 2px solid transparent;\n            transition: transform 0.1s;\n            outline: 2px solid transparent;\n            outline-offset: 2px;\n        }\n\n        .swatch:hover { transform: scale(1.13); }\n        .swatch.sel { outline-color: #00CFFF; }\n\n        .sw-tip {\n            position: absolute;\n            bottom: calc(100% + 5px);\n            left: 50%;\n            transform: translateX(-50%);\n            background: rgba(255,255,255,0.08);\n            border: 1px solid #383838;\n            color: #ddd;\n            font-size: 10px;\n            padding: 3px 7px;\n            border-radius: 4px;\n            white-space: nowrap;\n            pointer-events: none;\n            opacity: 0;\n            transition: opacity 0.1s;\n            z-index: 20;\n        }\n\n        .sw-wrap:hover .sw-tip { opacity: 1; }\n\n        /* Placement */\n        .place-list { display: flex; flex-direction: column; gap: 4px; }\n\n        .place-btn {\n            padding: 7px 10px;\n            border-radius: 5px;\n            border: 1px solid #232323;\n            background: #1e1e1e;\n            color: #888;\n            font-size: 12px;\n            cursor: pointer;\n            text-align: left;\n            transition: all 0.1s;\n            user-select: none;\n            display: flex;\n            align-items: center;\n            gap: 7px;\n        }\n\n        .place-btn:hover { border-color: #363636; color: #ddd; }\n        .place-btn.sel { border-color: #00CFFF; color: #fff; background: rgba(0,207,255,0.15); }\n        .pi { font-size: 13px; width: 16px; text-align: center; flex-shrink: 0; }\n\n        /* Sizes */\n        .size-grid { display: flex; flex-wrap: wrap; gap: 5px; }\n\n        .size-btn {\n            min-width: 38px;\n            height: 32px;\n            padding: 0 8px;\n            border-radius: 4px;\n            border: 1px solid #232323;\n            background: #1e1e1e;\n            color: #888;\n            font-size: 11px;\n            font-weight: 600;\n            cursor: pointer;\n            transition: all 0.1s;\n            user-select: none;\n        }\n\n        .size-btn:hover { border-color: #363636; color: #ddd; }\n        .size-btn.sel { border-color: #00CFFF; color: #fff; background: rgba(0,207,255,0.15); }\n\n        /* Qty */\n        .qty-row {\n            display: flex;\n            align-items: center;\n            border: 1px solid rgba(255,255,255,0.08);\n            border-radius: 5px;\n            overflow: hidden;\n            width: fit-content;\n        }\n\n        .qty-btn {\n            width: 32px;\n            height: 32px;\n            background: #1e1e1e;\n            border: none;\n            color: #999;\n            font-size: 17px;\n            cursor: pointer;\n            transition: all 0.1s;\n        }\n\n        .qty-btn:hover { background: rgba(255,255,255,0.08); color: #fff; }\n\n        .qty-val {\n            width: 48px;\n            height: 32px;\n            background: #161616;\n            border: none;\n            border-left: 1px solid rgba(255,255,255,0.08);\n            border-right: 1px solid rgba(255,255,255,0.08);\n            color: #fff;\n            font-size: 13px;\n            font-weight: 700;\n            text-align: center;\n        }\n\n        /* Notes */\n        .notes-ta {\n            width: 100%;\n            background: #1e1e1e;\n            border: 1px solid rgba(255,255,255,0.08);\n            border-radius: 5px;\n            color: #bbb;\n            padding: 8px 10px;\n            font-size: 12px;\n            resize: vertical;\n            min-height: 60px;\n            font-family: inherit;\n            line-height: 1.5;\n            transition: border-color 0.1s;\n        }\n\n        .notes-ta:focus { outline: none; border-color: #383838; }\n        .notes-ta::placeholder { color: #475569; }\n\n        .divider { height: 1px; background: #202020; margin: 14px 0; }\n\n        /* Preview */\n        .preview {\n            display: grid;\n            grid-template-rows: 1fr auto;\n            background: #0e0e0e;\n            min-height: 0;\n            min-width: 0;\n            overflow: hidden;\n        }\n\n        .stage {\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            padding: 16px;\n            position: relative;\n            overflow: hidden;\n            min-height: 0;\n            min-width: 0;\n        }\n\n        .mockup-wrap {\n            position: relative;\n            max-width: 430px;\n            width: 100%;\n            max-height: 100%;\n            background: #F1F5F9;\n            border-radius: 10px;\n            overflow: hidden;\n            isolation: isolate; /* keeps multiply blend inside the wrap, away from dark stage */\n            box-shadow: 0 8px 40px rgba(0,0,0,0.5);\n            display: flex;\n            align-items: center;\n            justify-content: center;\n        }\n\n        .mockup-img {\n            width: auto;\n            max-width: 100%;\n            height: auto;\n            max-height: 100%;\n            display: block;\n            margin: 0 auto;\n            object-fit: contain;\n        }\n\n\n        .mockup-ph {\n            width: 100%;\n            max-width: 430px;\n            min-height: 340px;\n            background: #171717;\n            border-radius: 10px;\n            border: 2px dashed #242424;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            gap: 10px;\n            color: #333;\n        }\n\n        .ph-icon { font-size: 48px; }\n        .ph-msg { font-size: 13px; text-align: center; max-width: 220px; line-height: 1.6; color: #475569; }\n\n        /* Colour note badge */\n        .colour-note {\n            position: absolute;\n            top: 28px;\n            right: 28px;\n            background: #1e1e1e;\n            border: 1px solid rgba(255,255,255,0.08);\n            border-radius: 5px;\n            padding: 5px 10px;\n            font-size: 11px;\n            color: #94A3B8;\n            display: none;\n        }\n\n        .colour-note.visible { display: block; }\n\n        .colour-dot {\n            display: inline-block;\n            width: 10px;\n            height: 10px;\n            border-radius: 50%;\n            margin-right: 5px;\n            vertical-align: middle;\n            border: 1px solid rgba(255,255,255,0.15);\n        }\n\n        /* Placement dot */\n        .pdot {\n            position: absolute;\n            width: 24px;\n            height: 24px;\n            border-radius: 50%;\n            background: rgba(0,207,255,0.9);\n            border: 2px solid #fff;\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            font-size: 9px;\n            font-weight: 900;\n            color: #fff;\n            opacity: 0;\n            transform: translate(-50%, -50%) scale(0.4);\n            transition: opacity 0.2s, transform 0.2s;\n            box-shadow: 0 2px 8px rgba(0,0,0,0.6);\n            pointer-events: none;\n            z-index: 5;\n        }\n\n        .pdot.show { opacity: 1; transform: translate(-50%, -50%) scale(1); }\n\n        /* Summary bar\n           Two-row layout: top row holds the fields cluster (left) and the\n           action buttons cluster (right, pushed by margin-left:auto). On\n           narrow viewports flex-wrap lets the actions drop to a new line\n           while staying grouped. The tip lives in a thin row below. */\n        .sum-bar {\n            background: #141414;\n            border-top: 1px solid #222;\n            padding: 10px 22px 8px;\n            display: flex;\n            flex-direction: column;\n            gap: 4px;\n            flex-shrink: 0;\n            /* Resizable height driven by --sum-height (set by the horizontal\n               splitter). Clamped to a min that fits the current single row +\n               actions, and a max of 50vh so the canvas can't be squeezed out. */\n            height: clamp(112px, var(--sum-height, 120px), 50vh);\n            overflow-y: auto;\n            scrollbar-width: thin;\n            scrollbar-color: rgba(255,255,255,0.08) transparent;\n        }\n\n        .sum-row {\n            display: flex;\n            align-items: center;\n            gap: 18px;\n            flex-wrap: wrap;\n            width: 100%;\n        }\n\n        .sum-fields {\n            display: flex;\n            align-items: center;\n            gap: 18px;\n            flex-wrap: wrap;\n            flex: 1 1 auto;\n            min-width: 0;\n        }\n\n        .si { display: flex; flex-direction: column; gap: 2px; }\n\n        .sk {\n            font-size: 9px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 0.7px;\n            color: #475569;\n        }\n\n        .sv { font-size: 12px; font-weight: 600; color: #ccc; }\n        .sv.dim { color: #333; font-style: italic; font-weight: 400; }\n\n        /* Inline editable Qty in the summary bar. Mirrors the sidebar qty\n           input visually (#0A1020 navy fill, cyan focus ring) but compact\n           enough to sit between the other summary fields without wrapping\n           the row. Browser spinners stripped — users type a value directly\n           or use the sidebar +/- buttons. */\n        .s-input {\n            width: 64px;\n            height: 26px;\n            background: #0A1020;\n            border: 1px solid rgba(255,255,255,0.08);\n            border-radius: 4px;\n            color: #fff;\n            font-size: 12px;\n            font-weight: 600;\n            font-family: inherit;\n            padding: 2px 8px;\n            text-align: center;\n            outline: none;\n            transition: border-color 0.12s, box-shadow 0.12s;\n            -moz-appearance: textfield;\n        }\n        .s-input:hover { border-color: rgba(0,207,255,0.45); }\n        .s-input:focus {\n            border-color: #00CFFF;\n            box-shadow: 0 0 0 2px rgba(0,207,255,0.18);\n        }\n        .s-input::-webkit-outer-spin-button,\n        .s-input::-webkit-inner-spin-button {\n            -webkit-appearance: none;\n            margin: 0;\n        }\n\n        .sum-actions {\n            margin-left: auto;\n            display: flex;\n            gap: 7px;\n            flex-shrink: 0;\n            flex-wrap: nowrap;\n        }\n\n        .sum-tip {\n            color: #475569;\n            font-size: 10px;\n            line-height: 1.4;\n            width: 100%;\n            text-align: right;\n        }\n\n        .btn {\n            padding: 7px 14px;\n            border-radius: 5px;\n            font-size: 12px;\n            font-weight: 600;\n            cursor: pointer;\n            border: none;\n            transition: all 0.1s;\n        }\n\n        .btn-ghost { background: #1c1c1c; border: 1px solid rgba(255,255,255,0.08); color: #999; }\n        .btn-ghost:hover { background: #222; color: #fff; }\n        /* WCAG AA: dark text on cyan (contrast ratio ~9.5:1). Do NOT use #fff here. */\n        .btn-primary { background: #00CFFF; color: #0A1020; }\n        .btn-primary:hover { background: #00B8E6; color: #0A1020; }\n\n        /* Dual canvas (front + back) */\n        .dual-wrap {\n            display: flex;\n            gap: 16px;\n            align-items: stretch;\n            justify-content: center;\n            width: 100%;\n            max-height: 100%;\n            padding: 8px 16px;\n            min-height: 0;\n        }\n\n        .view-item {\n            flex: 1 1 0;\n            max-width: 390px;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            gap: 6px;\n            min-width: 0;\n            min-height: 0;\n            max-height: 100%;\n        }\n\n        .view-label {\n            font-size: 10px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 1.2px;\n            color: #475569;\n            flex-shrink: 0;\n        }\n\n        .canvas-dual {\n            width: auto;\n            max-width: 100%;\n            height: auto;\n            max-height: 100%;\n            min-height: 0;\n            display: block;\n            border-radius: 8px;\n            background: #F1F5F9;\n            box-shadow: 0 6px 28px rgba(0,0,0,0.45);\n            object-fit: contain;\n        }\n\n        /* Logo upload */\n        .logo-drop {\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            justify-content: center;\n            gap: 6px;\n            padding: 14px 10px;\n            border-radius: 6px;\n            border: 1px dashed #2e2e2e;\n            background: #0A1020;\n            color: #94A3B8;\n            font-size: 12px;\n            cursor: pointer;\n            transition: all 0.12s;\n            width: 100%;\n            text-align: center;\n        }\n\n        .logo-drop:hover, .logo-drop.drag-over {\n            border-color: #00CFFF;\n            color: #00CFFF;\n            background: rgba(0,207,255,0.15);\n        }\n\n        .logo-drop input { display: none; }\n        .logo-drop-icon { font-size: 22px; }\n\n        .logo-loaded {\n            display: none;\n            margin-top: 10px;\n            flex-direction: column;\n            gap: 8px;\n        }\n\n        .logo-loaded.show { display: flex; }\n\n        .logo-thumb {\n            width: 100%;\n            max-height: 72px;\n            object-fit: contain;\n            background: repeating-conic-gradient(#222 0% 25%, #0A1020 0% 50%) 0 0 / 10px 10px;\n            border-radius: 4px;\n            border: 1px solid rgba(255,255,255,0.08);\n            padding: 6px;\n        }\n\n        .logo-size-row {\n            display: flex;\n            align-items: center;\n            gap: 8px;\n        }\n\n        .logo-size-row span {\n            font-size: 10px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 0.7px;\n            color: #475569;\n            white-space: nowrap;\n        }\n\n        .logo-size-row input[type=range] {\n            flex: 1;\n            accent-color: #00CFFF;\n            height: 3px;\n        }\n\n        .logo-size-val {\n            font-size: 11px;\n            color: #94A3B8;\n            min-width: 30px;\n            text-align: right;\n        }\n\n        .logo-remove {\n            padding: 5px 10px;\n            border-radius: 4px;\n            background: transparent;\n            border: 1px solid rgba(255,255,255,0.08);\n            color: #94A3B8;\n            font-size: 11px;\n            cursor: pointer;\n            transition: all 0.1s;\n            align-self: flex-start;\n        }\n\n        .logo-remove:hover { border-color: #c0392b; color: #c0392b; }\n\n        /* Logo position offsets */\n        .logo-offsets { margin-top: 10px; display: flex; flex-direction: column; gap: 5px; }\n\n        .offset-row {\n            display: flex;\n            align-items: center;\n            gap: 7px;\n        }\n\n        .offset-icon { font-size: 12px; color: #475569; width: 14px; flex-shrink: 0; text-align: center; }\n\n        .offset-lbl { font-size: 10px; color: #475569; width: 14px; flex-shrink: 0; }\n\n        .offset-row input[type=range] {\n            flex: 1;\n            accent-color: #00CFFF;\n            height: 3px;\n        }\n\n        .offset-val { font-size: 10px; color: #94A3B8; min-width: 22px; text-align: right; }\n\n        /* Quote panel — overrides .preview grid rows to include the quote drawer.\n           Rows: stage (1fr) | horizontal splitter (auto, 6px) | summary bar\n           (auto, clamp height) | quote panel (auto, drawer). */\n        .preview {\n            display: grid;\n            grid-template-rows: 1fr auto auto auto;\n            background: #0e0e0e;\n            min-height: 0;\n            min-width: 0;\n            overflow: hidden;\n        }\n\n        .quote-panel {\n            background: #141414;\n            border-top: 1px solid rgba(255,255,255,0.08);\n            height: 200px;\n            overflow-y: auto;\n            scrollbar-width: thin;\n            scrollbar-color: rgba(255,255,255,0.08) transparent;\n            transition: height 0.2s ease;\n        }\n\n        .quote-panel.collapsed {\n            height: 0;\n            border-top: none;\n            overflow: hidden;\n        }\n\n        .qp-header {\n            display: flex;\n            align-items: center;\n            gap: 10px;\n            padding: 8px 18px;\n            border-bottom: 1px solid #1e1e1e;\n            font-size: 11px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 0.7px;\n            color: #94A3B8;\n            position: sticky;\n            top: 0;\n            background: #141414;\n        }\n\n        .qp-total-badge {\n            margin-left: auto;\n            font-size: 12px;\n            font-weight: 700;\n            color: #00CFFF;\n        }\n\n        .qp-clear {\n            background: none;\n            border: none;\n            color: #444;\n            font-size: 11px;\n            cursor: pointer;\n            padding: 2px 6px;\n        }\n        .qp-clear:hover { color: #c0392b; }\n\n        .qp-list { padding: 6px 0; }\n\n        .qp-item {\n            display: flex;\n            align-items: center;\n            gap: 12px;\n            padding: 10px 18px;\n            border-bottom: 1px solid #0A1020;\n            font-size: 12px;\n        }\n\n        .qp-item:last-child { border-bottom: none; }\n\n        .qp-item-thumb {\n            display: flex;\n            gap: 6px;\n            flex-shrink: 0;\n            align-items: center;\n        }\n\n        .qp-thumb {\n            width: auto;\n            height: 110px;\n            object-fit: contain;\n            background: #F1F5F9;\n            border-radius: 5px;\n        }\n\n        .qp-item-info { flex: 1; min-width: 0; }\n        .qp-item-name { font-weight: 600; color: #ddd; }\n        .qp-item-desc { color: #94A3B8; font-size: 11px; margin-top: 2px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n\n        .qp-item-price {\n            text-align: right;\n            flex-shrink: 0;\n        }\n\n        .qp-item-total { font-weight: 700; color: #F1F5F9; font-size: 13px; }\n        .qp-item-unit  { color: #444; font-size: 10px; margin-top: 1px; }\n\n        .qp-remove {\n            background: none; border: none;\n            color: #333; font-size: 14px;\n            cursor: pointer; padding: 2px 4px;\n            flex-shrink: 0;\n        }\n        .qp-remove:hover { color: #c0392b; }\n\n        /* Print quote */\n        #print-quote { display: none; }\n\n        .print-header,\n        .print-footer-mark { display: none; }\n\n        @page { margin: 12mm 12mm 18mm 12mm; }\n\n        @media print {\n            html, body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }\n            body > *:not(#print-quote):not(.print-header):not(.print-footer-mark) { display: none !important; }\n            #print-quote {\n                display: block !important;\n                font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;\n                font-size: 12px;\n                color: #111;\n                background: #fff;\n                padding: 32px 40px;\n            }\n            .print-header {\n                display: flex !important;\n                position: fixed;\n                top: 6mm;\n                left: 12mm;\n                align-items: center;\n                gap: 8px;\n                color: #111;\n                font-size: 12px;\n                font-weight: 800;\n                letter-spacing: 0.4px;\n                z-index: 9999;\n            }\n            .print-header img { height: 40px; width: auto; color: #111; }\n            .print-footer-mark {\n                display: flex !important;\n                position: fixed;\n                bottom: 6mm;\n                right: 12mm;\n                opacity: 0.5;\n                z-index: 9999;\n            }\n            .print-footer-mark img { height: 20px; width: auto; color: #111; }\n        }\n\n        .pq-header {\n            display: flex;\n            justify-content: space-between;\n            align-items: flex-start;\n            margin-bottom: 28px;\n            padding-bottom: 16px;\n            border-bottom: 2px solid #111;\n        }\n\n        .pq-brand { font-size: 22px; font-weight: 800; letter-spacing: -0.5px; }\n        .pq-brand span { color: #00CFFF; }\n\n        .pq-meta { text-align: right; }\n        .pq-quote-num { font-size: 15px; font-weight: 700; }\n        .pq-date { color: #666; margin-top: 2px; }\n\n        .pq-table {\n            width: 100%;\n            border-collapse: collapse;\n            margin-bottom: 20px;\n        }\n\n        .pq-table th {\n            background: #111;\n            color: #fff;\n            padding: 8px 12px;\n            text-align: left;\n            font-size: 11px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 0.5px;\n        }\n\n        .pq-table th:last-child,\n        .pq-table td:last-child { text-align: right; }\n\n        .pq-table th:nth-child(3),\n        .pq-table td:nth-child(3) { text-align: center; }\n\n        .pq-table td {\n            padding: 10px 12px;\n            border-bottom: 1px solid #F1F5F9;\n            vertical-align: top;\n        }\n\n        .pq-item-label { font-weight: 700; font-size: 13px; margin-bottom: 4px; }\n        .pq-desc { color: #444; line-height: 1.7; font-size: 11px; }\n\n        .pq-totals {\n            margin-left: auto;\n            width: 240px;\n            border-top: 2px solid #111;\n            padding-top: 10px;\n        }\n\n        .pq-total-row {\n            display: flex;\n            justify-content: space-between;\n            padding: 4px 0;\n            font-size: 12px;\n            color: #444;\n        }\n\n        .pq-grand {\n            font-size: 15px;\n            font-weight: 800;\n            color: #111;\n            border-top: 1px solid #ccc;\n            margin-top: 6px;\n            padding-top: 8px;\n        }\n\n        .pq-footer {\n            margin-top: 32px;\n            color: #888;\n            font-size: 11px;\n            border-top: 1px solid #F1F5F9;\n            padding-top: 12px;\n        }\n        /* Customer request modal */\n        .rq-overlay {\n            display: none;\n            position: fixed;\n            inset: 0;\n            background: rgba(0,0,0,0.72);\n            z-index: 100;\n            align-items: center;\n            justify-content: center;\n        }\n        .rq-overlay.open { display: flex; }\n\n        .rq-modal {\n            background: #1e1e1e;\n            border: 1px solid #2e2e2e;\n            border-radius: 10px;\n            padding: 28px 30px;\n            width: 100%;\n            max-width: 420px;\n            box-shadow: 0 16px 60px rgba(0,0,0,0.7);\n        }\n\n        .rq-modal h2 {\n            font-size: 16px;\n            font-weight: 700;\n            color: #fff;\n            margin-bottom: 6px;\n        }\n\n        .rq-modal p {\n            font-size: 12px;\n            color: #94A3B8;\n            margin-bottom: 22px;\n            line-height: 1.5;\n        }\n\n        .rq-field { margin-bottom: 14px; }\n\n        .rq-field label {\n            display: block;\n            font-size: 10px;\n            font-weight: 700;\n            text-transform: uppercase;\n            letter-spacing: 0.8px;\n            color: #475569;\n            margin-bottom: 6px;\n        }\n\n        .rq-field input {\n            width: 100%;\n            background: #161616;\n            border: 1px solid rgba(255,255,255,0.08);\n            border-radius: 5px;\n            color: #ddd;\n            padding: 9px 12px;\n            font-size: 13px;\n            font-family: inherit;\n            outline: none;\n            transition: border-color 0.1s;\n        }\n\n        .rq-field input:focus { border-color: #00CFFF; }\n        .rq-field input::placeholder { color: #333; }\n\n        .rq-actions {\n            display: flex;\n            gap: 8px;\n            margin-top: 22px;\n        }\n\n        .rq-status {\n            font-size: 12px;\n            margin-top: 14px;\n            text-align: center;\n            min-height: 18px;\n        }\n\n        .rq-status.ok  { color: #7dd87d; }\n        .rq-status.err { color: #e05050; }\n"}}),(0,o.jsx)("div",{dangerouslySetInnerHTML:{__html:'\n<div class="mockup-shell">\n\n<header>\n    <h1>Nova<span>merch</span> Mockup Builder</h1>\n    <small>Internal Design Tool</small>\n</header>\n\n\x3c!-- Product tab bar --\x3e\n<div class="product-bar" id="product-bar"></div>\n\n<div class="main">\n\n    \x3c!-- Options panel --\x3e\n    <div class="opts">\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Style</div>\n            <div class="style-list" id="style-list"></div>\n        </div>\n\n        <div class="divider"></div>\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Colour</div>\n            <div class="swatches" id="swatches"></div>\n        </div>\n\n        <div class="divider"></div>\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Front Logo</div>\n            <label class="logo-drop"\n                   ondragover="event.preventDefault(); this.classList.add(\'drag-over\')"\n                   ondragleave="this.classList.remove(\'drag-over\')"\n                   ondrop="event.preventDefault(); this.classList.remove(\'drag-over\'); handleLogoFile(\'front\', event.dataTransfer.files[0])">\n                <input type="file" id="logo-file-front" accept="image/*"\n                       onchange="handleLogoFile(\'front\', this.files[0])">\n                <span class="logo-drop-icon">&#127912;&#65039;</span>\n                <span>Click or drag &amp; drop</span>\n                <span style="font-size:10px; color:#475569;">PNG, SVG, JPG</span>\n            </label>\n            <div class="logo-loaded" id="logo-loaded-front">\n                <img class="logo-thumb" id="logo-thumb-front" src="" alt="">\n                <div class="logo-size-row">\n                    <span>Size</span>\n                    <input type="range" min="3" max="50" value="20" id="logo-size-front"\n                           oninput="onLogoSize(\'front\', this.value)">\n                    <span class="logo-size-val" id="logo-size-val-front">20%</span>\n                </div>\n                <button class="logo-remove" onclick="removeLogo(\'front\')">&#10005; Remove</button>\n            </div>\n        </div>\n\n        <div class="divider"></div>\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Logo Placement</div>\n            <div class="place-list" id="place-list-front"></div>\n            <div class="logo-offsets">\n                <div class="offset-row">\n                    <span class="offset-icon">&#8596;</span>\n                    <span class="offset-lbl">H</span>\n                    <input type="range" min="-30" max="30" value="0" id="offset-front-x"\n                           oninput="onOffsetChange(\'front\',\'x\',this.value)">\n                    <span class="offset-val" id="offset-front-x-val">0</span>\n                </div>\n                <div class="offset-row">\n                    <span class="offset-icon">&#8597;</span>\n                    <span class="offset-lbl">V</span>\n                    <input type="range" min="-30" max="30" value="0" id="offset-front-y"\n                           oninput="onOffsetChange(\'front\',\'y\',this.value)">\n                    <span class="offset-val" id="offset-front-y-val">0</span>\n                </div>\n            </div>\n        </div>\n\n        \x3c!-- Back logo + placement only shown for products with a back view --\x3e\n        <div id="back-logo-wrap" style="display:none;">\n            <div class="divider"></div>\n\n            <div class="opt-sec">\n                <div class="opt-lbl">Back Logo</div>\n                <label class="logo-drop"\n                       ondragover="event.preventDefault(); this.classList.add(\'drag-over\')"\n                       ondragleave="this.classList.remove(\'drag-over\')"\n                       ondrop="event.preventDefault(); this.classList.remove(\'drag-over\'); handleLogoFile(\'back\', event.dataTransfer.files[0])">\n                    <input type="file" id="logo-file-back" accept="image/*"\n                           onchange="handleLogoFile(\'back\', this.files[0])">\n                    <span class="logo-drop-icon">&#127912;&#65039;</span>\n                    <span>Click or drag &amp; drop</span>\n                    <span style="font-size:10px; color:#475569;">PNG, SVG, JPG</span>\n                </label>\n                <div class="logo-loaded" id="logo-loaded-back">\n                    <img class="logo-thumb" id="logo-thumb-back" src="" alt="">\n                    <div class="logo-size-row">\n                        <span>Size</span>\n                        <input type="range" min="3" max="50" value="20" id="logo-size-back"\n                               oninput="onLogoSize(\'back\', this.value)">\n                        <span class="logo-size-val" id="logo-size-val-back">20%</span>\n                    </div>\n                    <button class="logo-remove" onclick="removeLogo(\'back\')">&#10005; Remove</button>\n                </div>\n            </div>\n\n            <div class="divider"></div>\n\n            <div class="opt-sec">\n                <div class="opt-lbl">Back Logo Placement</div>\n                <div class="place-list" id="place-list-back"></div>\n                <div class="logo-offsets">\n                    <div class="offset-row">\n                        <span class="offset-icon">&#8596;</span>\n                        <span class="offset-lbl">H</span>\n                        <input type="range" min="-30" max="30" value="0" id="offset-back-x"\n                               oninput="onOffsetChange(\'back\',\'x\',this.value)">\n                        <span class="offset-val" id="offset-back-x-val">0</span>\n                    </div>\n                    <div class="offset-row">\n                        <span class="offset-icon">&#8597;</span>\n                        <span class="offset-lbl">V</span>\n                        <input type="range" min="-30" max="30" value="0" id="offset-back-y"\n                               oninput="onOffsetChange(\'back\',\'y\',this.value)">\n                        <span class="offset-val" id="offset-back-y-val">0</span>\n                    </div>\n                </div>\n            </div>\n        </div>\n\n        \x3c!-- Sock text only shown when socks is the active product --\x3e\n        <div id="sock-text-wrap" style="display:none;">\n            <div class="divider"></div>\n            <div class="opt-sec">\n                <div class="opt-lbl">Sock Text</div>\n                <input type="text" id="sock-text-input"\n                       style="width:100%; background:#1e1e1e; border:1px solid rgba(255,255,255,0.08); border-radius:5px; color:#bbb; padding:8px 10px; font-size:12px; font-family:inherit; outline:none;"\n                       placeholder="e.g. Team name, player number..."\n                       oninput="onSockTextInput()">\n                <div style="margin-top:9px;">\n                    <div class="opt-lbl" style="margin-bottom:6px;">Text Placement</div>\n                    <div class="place-list" id="sock-text-place-list"></div>\n                </div>\n                <div style="margin-top:9px;">\n                    <div class="opt-lbl" style="margin-bottom:6px;">Text Colour</div>\n                    <label style="display:flex; align-items:center; gap:10px; background:#1e1e1e; border:1px solid #475569; border-radius:8px; padding:8px 10px; cursor:pointer; width:fit-content;"\n                           title="Click to open colour picker">\n                        <input type="color" id="sock-text-colour-picker" value="#111111"\n                               style="width:28px; height:28px; padding:0; border:none; border-radius:4px; background:none; cursor:pointer; flex-shrink:0;"\n                               oninput="pickSockTextColour(this.value)">\n                        <input type="text" id="sock-text-colour-hex" value="#111111" maxlength="7"\n                               style="width:72px; background:transparent; border:none; color:#ddd; font-size:13px; font-family:inherit; outline:none; cursor:text;"\n                               oninput="onSockTextHexInput(this.value)"\n                               onclick="event.stopPropagation()">\n                        <span style="color:#888; font-size:11px; white-space:nowrap;">Pick colour</span>\n                    </label>\n                </div>\n            </div>\n        </div>\n\n        \x3c!-- Decoration only shown for drinkware --\x3e\n        <div id="decoration-wrap" style="display:none;">\n            <div class="divider"></div>\n            <div class="opt-sec">\n                <div class="opt-lbl">Logo Style</div>\n                <div class="style-list" id="decoration-list"></div>\n            </div>\n        </div>\n\n        <div class="divider"></div>\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Size</div>\n            <div class="size-grid" id="size-grid"></div>\n        </div>\n\n        <div class="divider"></div>\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Quantity</div>\n            <div class="qty-row">\n                <button class="qty-btn" onclick="changeQty(-1)">&#8722;</button>\n                <input  class="qty-val" id="qty" type="number" value="1" min="1" max="100000" oninput="updateSummary()">\n                <button class="qty-btn" onclick="changeQty(1)">&#43;</button>\n            </div>\n        </div>\n\n        <div class="divider"></div>\n\n        <div class="opt-sec">\n            <div class="opt-lbl">Notes / Special Instructions</div>\n            <textarea class="notes-ta" id="notes"\n                placeholder="e.g. Pantone ref, logo filename, placement dimensions, thread colour..."\n                oninput="updateSummary()"></textarea>\n        </div>\n\n    </div>\n\n    \x3c!-- Splitter (draggable handle between sidebar and preview) --\x3e\n    <div class="splitter" id="splitter"\n         role="separator"\n         aria-label="Resize sidebar"\n         aria-orientation="vertical"\n         tabindex="0"></div>\n\n    \x3c!-- Preview --\x3e\n    <div class="preview">\n        <div class="stage">\n            \x3c!-- Placeholder shown while no product is selected or image is loading --\x3e\n            <div id="mockup-ph" class="mockup-ph">\n                <div class="ph-icon" id="ph-icon">&#128085;</div>\n                <div class="ph-msg" id="ph-msg">Select a product above to load its mockup.</div>\n            </div>\n\n            \x3c!-- Single view --\x3e\n            <div class="mockup-wrap" id="mockup-wrap" style="display:none;">\n                <canvas id="mockup-canvas" class="mockup-img"></canvas>\n            </div>\n\n            \x3c!-- Dual view: front + back side by side --\x3e\n            <div id="dual-wrap" class="dual-wrap" style="display:none;">\n                <div class="view-item">\n                    <canvas id="canvas-front" class="canvas-dual"></canvas>\n                    <div class="view-label">Front</div>\n                </div>\n                <div class="view-item">\n                    <canvas id="canvas-back" class="canvas-dual"></canvas>\n                    <div class="view-label">Back</div>\n                </div>\n            </div>\n\n            \x3c!-- Colour badge --\x3e\n            <div class="colour-note" id="colour-note">\n                <span class="colour-dot" id="colour-dot"></span>\n                <span id="colour-note-text">Selected colour</span>\n            </div>\n        </div>\n\n        \x3c!-- Horizontal splitter — drag handle between canvas stage and summary bar --\x3e\n        <div class="splitter-h" id="splitter-h"\n             role="separator"\n             aria-label="Resize summary bar"\n             aria-orientation="horizontal"\n             tabindex="0"></div>\n\n        \x3c!-- Summary bar --\x3e\n        <div class="sum-bar">\n            <div class="sum-row">\n                <div class="sum-fields">\n                    <div class="si"><div class="sk">Product</div><div class="sv dim" id="s-product">-</div></div>\n                    <div class="si"><div class="sk">Style</div><div class="sv dim" id="s-style">-</div></div>\n                    <div class="si"><div class="sk">Colour</div><div class="sv dim" id="s-colour">-</div></div>\n                    <div class="si"><div class="sk">Placement</div><div class="sv dim" id="s-placement">-</div></div>\n                    <div class="si"><div class="sk">Logo Style</div><div class="sv dim" id="s-decoration">-</div></div>\n                    <div class="si"><div class="sk">Size</div><div class="sv dim" id="s-size">-</div></div>\n                    <div class="si"><div class="sk">Qty</div><input class="s-input" id="s-qty" type="number" min="1" max="100000" step="1" value="1" oninput="onSummaryQtyInput(this.value)" onchange="onSummaryQtyCommit(this.value)"></div>\n                    <div class="si"><div class="sk">Unit Price</div><div class="sv dim" id="s-unit-price">-</div></div>\n                    <div class="si"><div class="sk">Line Total</div><div class="sv dim" id="s-line-total">-</div></div>\n                </div>\n                <div class="sum-actions">\n                    <button class="btn btn-ghost" onclick="resetAll()">Reset</button>\n                    <button class="btn btn-ghost" id="copy-btn" onclick="copySpec()">Copy Spec</button>\n                    <button class="btn btn-ghost" onclick="addToQuote()" id="add-quote-btn">+ Add to Basket</button>\n                    <button class="btn btn-ghost" id="toggle-quote-btn" onclick="toggleQuotePanel()" style="display:none;">Basket &#9650;</button>\n                    <button class="btn btn-primary" onclick="requestQuote()" id="print-btn">Request Quote</button>\n                </div>\n            </div>\n            <div class="sum-tip">Tip: in the browser print dialog, set Headers and Footers to "Off" to hide the URL in the corners.</div>\n        </div>\n\n        \x3c!-- Quote panel --\x3e\n        <div class="quote-panel" id="quote-panel" style="display:none;">\n            <div class="qp-header">\n                <span>Basket</span>\n                <span id="qp-count">0 items</span>\n                <span class="qp-total-badge" id="qp-grand-total"></span>\n                <button class="qp-clear" onclick="clearQuote()">Clear all</button>\n            </div>\n            <div class="qp-list" id="qp-list"></div>\n        </div>\n    </div>\n\n</div>\n</div>\x3c!-- /.mockup-shell --\x3e\n\n\x3c!-- Print quote populated by JS, visible only when printing --\x3e\n<div id="print-quote"></div>\n\n\x3c!-- Print-only logo header and footer mark --\x3e\n<div class="print-header"><img src="/logo.svg" alt="Nova Merch" /><span>NOVA MERCH</span></div>\n<div class="print-footer-mark"><img src="/logo.svg" alt="Nova Merch" /></div>\n\n\x3c!-- Customer info modal for Request Quote --\x3e\n<div class="rq-overlay" id="rq-overlay">\n    <div class="rq-modal">\n        <h2>Request a Quote</h2>\n        <p>Fill in your details and we\'ll send you a formal quote shortly.</p>\n        <div class="rq-field">\n            <label>Full Name <span style="color:#00CFFF">*</span></label>\n            <input type="text" id="rq-name" placeholder="e.g. Jane Smith" autocomplete="name">\n        </div>\n        <div class="rq-field">\n            <label>Email Address <span style="color:#00CFFF">*</span></label>\n            <input type="email" id="rq-email" placeholder="e.g. jane@example.com" autocomplete="email">\n        </div>\n        <div class="rq-field">\n            <label>Phone Number <span style="color:#475569">(optional)</span></label>\n            <input type="tel" id="rq-phone" placeholder="e.g. 0412 345 678" autocomplete="tel">\n        </div>\n        <div class="rq-actions">\n            <button class="btn btn-ghost" style="flex:1" onclick="closeRqModal()">Cancel</button>\n            <button class="btn btn-primary" style="flex:2" id="rq-send-btn" onclick="submitQuoteRequest()">Send Request</button>\n        </div>\n        <div class="rq-status" id="rq-status"></div>\n    </div>\n</div>\n\n'}})]})}},6194:(n,e,t)=>{Promise.resolve().then(t.bind(t,1203))}},n=>{n.O(0,[441,255,358],()=>n(n.s=6194)),_N_E=n.O()}]);